import { useState, useRef, useEffect } from "react";

const GROQ_API_KEY  = "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";
const GROQ_CHAT_URL = "https://api.groq.com/openai/v1/chat/completions";
const GROQ_STT_URL  = "https://api.groq.com/openai/v1/audio/transcriptions";
const STORAGE_KEY   = "aria_last_conversation";

export default function AudioCallTab({ topic, language }) {
  const [messages,   setMessages]   = useState([]);
  const [loading,    setLoading]    = useState(false);
  const [listening,  setListening]  = useState(false);
  const [transcript, setTranscript] = useState("");
  const [callActive, setCallActive] = useState(false);
  const [ariaStatus, setAriaStatus] = useState("idle");
  const [textInput,  setTextInput]  = useState("");
  const [micError,   setMicError]   = useState("");
  const [savedConvo, setSavedConvo] = useState(() => {
    try { return JSON.parse(localStorage.getItem(STORAGE_KEY)) || null; }
    catch { return null; }
  });

  const synthRef       = useRef(window.speechSynthesis);
  const mediaRecRef    = useRef(null);
  const audioChunksRef = useRef([]);
  const streamRef      = useRef(null);
  const messagesRef    = useRef([]);
  const messagesEndRef = useRef(null);

  function getLangCode(code) {
    const map = { es: "es-ES", fr: "fr-FR", de: "de-DE", ja: "ja-JP", pt: "pt-PT" };
    return map[code] || "en-US";
  }

  // Keep messagesRef in sync so cleanup/callbacks always see latest messages
  useEffect(() => { messagesRef.current = messages; }, [messages]);

  // Auto scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Cleanup on unmount (tab switch) ŌĆö stop audio and save conversation
  useEffect(() => {
    return () => {
      synthRef.current.cancel();
      stopMicStream();
      const msgs = messagesRef.current;
      if (msgs.length > 0) {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(msgs));
      }
    };
  }, []);

  function stopMicStream() {
    if (mediaRecRef.current && mediaRecRef.current.state !== "inactive") {
      try { mediaRecRef.current.stop(); } catch (_) {}
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop());
      streamRef.current = null;
    }
  }

  function startCall(resumedMessages = []) {
    setMessages(resumedMessages);
    setCallActive(true);
    setAriaStatus("idle");
    setMicError("");
    setTranscript("");
    if (resumedMessages.length === 0) {
      speakAria(`Hello! I'm Aria. Let's practice ${topic}. You can speak or type!`);
    } else {
      speakAria(`Welcome back! Let's continue our ${topic} practice.`);
    }
  }

  function endCall() {
    const msgs = messagesRef.current;
    if (msgs.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(msgs));
      setSavedConvo(msgs);
    }
    stopMicStream();
    synthRef.current.cancel();
    setCallActive(false);
    setAriaStatus("idle");
    setListening(false);
    setTranscript("");
    setMicError("");
  }

  // Click-to-toggle mic: tap once to start recording, tap again to send
  async function toggleMic() {
    if (ariaStatus === "thinking") return;

    if (listening) {
      // Stop recording -> triggers onstop -> transcribe & send
      setListening(false);
      if (mediaRecRef.current && mediaRecRef.current.state === "recording") {
        mediaRecRef.current.stop();
      }
      return;
    }

    // Stop Aria if she's speaking
    synthRef.current.cancel();
    setMicError("");
    setTranscript("­¤ÄÖ Starting microphone...");

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Pick best supported mime type
      const mimeType = ["audio/webm;codecs=opus", "audio/webm", "audio/ogg"]
        .find(t => MediaRecorder.isTypeSupported(t)) || "";

      const recorder = new MediaRecorder(stream, mimeType ? { mimeType } : undefined);
      audioChunksRef.current = [];
      mediaRecRef.current = recorder;

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) audioChunksRef.current.push(e.data);
      };

      recorder.onstop = async () => {
        // Release mic tracks
        streamRef.current?.getTracks().forEach(t => t.stop());
        streamRef.current = null;

        const chunks = audioChunksRef.current;
        audioChunksRef.current = [];

        if (!chunks.length) { setAriaStatus("idle"); setTranscript(""); return; }

        const blob = new Blob(chunks, { type: mimeType || "audio/webm" });
        if (blob.size < 500) { setAriaStatus("idle"); setTranscript(""); return; }

        setAriaStatus("thinking");
        setTranscript("­¤öä Transcribing your speech...");

        try {
          const ext = (mimeType || "audio/webm").includes("ogg") ? "ogg" : "webm";
          const formData = new FormData();
          formData.append("file", blob, `recording.${ext}`);
          formData.append("model", "whisper-large-v3");
          formData.append("language", language?.code || "en");

          const res  = await fetch(GROQ_STT_URL, {
            method: "POST",
            headers: { Authorization: `Bearer ${GROQ_API_KEY}` },
            body: formData,
          });
          const data = await res.json();
          const text = data?.text?.trim();

          setTranscript("");
          if (text) {
            sendToAria(text);
          } else {
            setMicError("Couldn't hear anything. Try again or type below.");
            setAriaStatus("idle");
          }
        } catch (err) {
          console.error("Transcription error:", err);
          setMicError("Transcription failed. Please type your message.");
          setTranscript("");
          setAriaStatus("idle");
        }
      };

      recorder.start();
      setListening(true);
      setAriaStatus("listening");
      setTranscript("");

    } catch (err) {
      console.error("Mic error:", err);
      setMicError("Microphone access denied. Allow microphone in browser settings.");
      setTranscript("");
      setAriaStatus("idle");
    }
  }

  async function sendToAria(text) {
    // Build full conversation history for context
    const history = messagesRef.current.map(m => ({
      role:    m.role === "aria" ? "assistant" : "user",
      content: m.text,
    }));

    setMessages(prev => [...prev, { role: "user", text }]);
    setAriaStatus("thinking");
    setLoading(true);

    try {
      const res = await fetch(GROQ_CHAT_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${GROQ_API_KEY}`,
        },
        body: JSON.stringify({
          model: "llama-3.3-70b-versatile",
          messages: [
            {
              role: "system",
              content: `You are Aria, a friendly conversational language tutor.
Topic: ${topic}. Student is learning: ${language?.name || "a language"}.
Rules:
- Respond in ONLY 1-3 short sentences to maintain natural conversation pace.
- Respond in ${language?.name || "the target language"} with English hints in [brackets] only when needed.
- Gently correct errors inline without stopping the conversation.
- Never go off topic. If off topic say: "Let's stay focused on our lesson!"`,
            },
            ...history,
            { role: "user", content: text },
          ],
          max_tokens: 120,
          temperature: 0.8,
        }),
      });

      const data  = await res.json();
      const reply = data?.choices?.[0]?.message?.content || "Sorry, I didn't catch that.";
      setMessages(prev => [...prev, { role: "aria", text: reply }]);
      speakAria(reply);

    } catch (err) {
      setMessages(prev => [...prev, { role: "aria", text: "Sorry, something went wrong." }]);
      setAriaStatus("idle");
    }

    setLoading(false);
  }

  function speakAria(text) {
    synthRef.current.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang  = getLangCode(language?.code);
    utterance.rate  = 0.95;
    utterance.pitch = 1.1;
    setAriaStatus("speaking");
    utterance.onend = () => setAriaStatus("idle");
    synthRef.current.speak(utterance);
  }

  function sendTextMessage() {
    if (!textInput.trim() || loading) return;
    const text = textInput.trim();
    setTextInput("");
    sendToAria(text);
  }

  const statusLabel = {
    idle:      "Tap ­¤ÄÖ to speak ŌĆö or type below",
    listening: "­¤ö┤ Recording... tap ­¤ÄÖ again to send",
    thinking:  "­¤ÆŁ Aria is thinking...",
    speaking:  "­¤öŖ Aria is speaking... (tap ­¤ÄÖ to interrupt)",
  }[ariaStatus];

  return (
    <div className="call-container">
      {!callActive ? (
        <div className="call-idle">
          <div className="call-avatar">­¤ż¢</div>
          <p className="call-aria-name">Aria</p>
          <p className="call-topic">Topic: <strong>{topic}</strong></p>
          <p className="call-lang">Language: <strong>{language?.name}</strong></p>
          <button className="call-start-btn" onClick={() => startCall()}>
            ­¤ō× Start Call
          </button>
          {savedConvo && savedConvo.length > 0 && (
            <button className="call-resume-btn" onClick={() => startCall(savedConvo)}>
              ­¤öü Resume Last Conversation
              <span className="call-resume-count">{savedConvo.length} messages</span>
            </button>
          )}
        </div>
      ) : (
        <div className="call-active">
          <div className="call-messages">
            {messages.map((msg, i) => (
              <div key={i} className={`call-bubble ${msg.role}`}>
                {msg.role === "aria" && <span className="call-name">Aria</span>}
                <p>{msg.text}</p>
              </div>
            ))}
            {ariaStatus === "thinking" && (
              <div className="call-bubble aria">
                <span className="call-name">Aria</span>
                <p className="typing">ŌŚÅ ŌŚÅ ŌŚÅ</p>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          <div className="call-controls">
            <p className="call-status">{statusLabel}</p>
            {transcript && <p className="call-transcript">{transcript}</p>}
            {micError   && <p className="call-mic-error">{micError}</p>}
            <button
              className={`call-mic-btn ${listening ? "active" : ""}`}
              onClick={toggleMic}
              disabled={ariaStatus === "thinking"}
            >
              {listening ? "­¤ö┤" : "­¤ÄÖ"}
            </button>
            <button className="call-end-btn" onClick={endCall}>­¤ōĄ End Call</button>
          </div>

          {/* Text input fallback */}
          <div className="chat-input-row">
            <input
              className="chat-input"
              value={textInput}
              onChange={(e) => setTextInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && sendTextMessage()}
              placeholder="Or type your message..."
              disabled={loading}
            />
            <button className="chat-send" onClick={sendTextMessage}>Ō×ż</button>
          </div>
        </div>
      )}
    </div>
  );
}
